import{_ as i,o as r,c as t,a as s}from"./app.aa2f9f99.js";var e="/images/diy/t2lt/t2lt-fertig-gebaut.jpeg",a="/images/diy/t2lt/t2lt-bauteile.jpeg",d="/images/diy/t2lt/t2lt-werkzeuge.jpeg",l="/images/diy/t2lt/t2lt-zeichnung-antennenaufbau.jpg",h="/images/diy/t2lt/t2lt-kabelende-abisoliert.jpeg",n="/images/diy/t2lt/t2lt-spule-gewickelt.jpeg",c="/images/diy/t2lt/t2lt-schrumpfschlauch-pre.jpeg",u="/images/diy/t2lt/t2lt-schrumpfschlauch-done.jpeg",m="/images/diy/t2lt/t2lt-schnur-schleife.jpeg",o="/images/diy/t2lt/t2lt-bnc-stecker.jpeg";const p={},g=s('<h1 id="t2lt-antenne-fur-2m-und-70cm" tabindex="-1"><a class="header-anchor" href="#t2lt-antenne-fur-2m-und-70cm" aria-hidden="true">#</a> T2LT Antenne f\xFCr 2m und 70cm</h1><p>Eine portable 2m und 70cm T2LT Antenne f\xFCr kleines Geld - selbstgebaut. Sehr einfach zu bauen und damit perfekt f\xFCr Einsteiger.</p><p><img src="'+e+'" alt="Fertig gebaute Antenne"></p><h2 id="bauteile" tabindex="-1"><a class="header-anchor" href="#bauteile" aria-hidden="true">#</a> Bauteile</h2><p>Die Antenne besteht im Wesentlichen aus einem einfachem RG-174 Koaxialkabel mit einer gewickelten Spule als Mantelwellensperre.</p><p><img src="'+a+'" alt="Bauteile"></p><ul><li>ca. 6,5 m an RG-174 Koax-Kabel (ca. 90 cm f\xFCr den Dipol-Teil und 75 cm f\xFCr die Mantelwellensperre. Zzgl. der gew\xFCnschten L\xE4nge an Zuleitung, hier ca. 5 m)</li><li>ca. 5 cm PVC oder HDPE-Rohr mit einem Durchmesser von 25 mm als Spulenk\xF6rper</li><li>ca. 5 cm Schrumpfschlauch mit ca. 50 mm Durchmesser vor dem Schrumpfen, um die Spule/Mantelwellensperre zu fixieren.</li><li>1 m Schnur, Durchmesser ca. 2 mm</li><li>ca. 90 cm Schrumpfschlau mit ca. 6 mm Durchmesser vor dem Schrumpfen, der den Dipol-Teil und Schnur zusammenh\xE4lt</li><li>BNC-Stecker passend zum Kabeldurchmesser zum Ancrimpen (oder anderer gew\xFCnschter Stecker)</li><li>Klett-Kabelbinder</li></ul><div class="custom-container tip"><p class="custom-container-title">Tipp</p><p>Wie bei allen Drau\xDFenfunker-Antennen k\xF6nnt ihr auf dem Discord-Server mal nachfragen, ob euch jemand ein Bastel-Kit f\xFCr diese Antenne zusammenstellen und zuschicken kann. Meistens hat noch genug Teile \xFCber und gibt diese gerne zum Selbstkostenpreis weiter.</p></div><h2 id="werkzeug" tabindex="-1"><a class="header-anchor" href="#werkzeug" aria-hidden="true">#</a> Werkzeug</h2><p><img src="'+d+'" alt="Werkzeuge"></p><ul><li>Abisolierzange</li><li>BNC-Crimpzange</li><li>ggf. einen L\xF6tkolben, je nach BNC-Stecker</li><li>Bohrer, 3 mm</li><li>Seitenschneider oder Kabelschere</li><li>Ma\xDFband oder Zollstock</li><li>Hei\xDFluftgebl\xE4se oder F\xF6hn</li><li>Stift oder Tape f\xFCr Markierungen</li></ul><h2 id="zusammenbau" tabindex="-1"><a class="header-anchor" href="#zusammenbau" aria-hidden="true">#</a> Zusammenbau</h2><p>Das Ziel besteht darin, die die unten abgebildete Konstruktion herzustellen. Die Ma\xDFe f\xFCr den Dipol-Teil rechts und die Mantelwellensperre sind kritisch, die L\xE4nge der Zuleitung (links) kann frei gew\xE4hlt werden bzw. ergibt sich aus dem Koax-Rest nach dem Herstellen des rechten Teils.</p><p><img src="'+l+'" alt="Zeichnung Antennenaufbau"></p><div class="custom-container tip"><p class="custom-container-title">Hinweis</p><p>Hinweis: Die Bilder dieses Artikels sind beim Aufbau in einer anderen Reihenfolge entstanden und werden bei Gelegenheit aktualisiert. Die textuelle Anleitung wurde hinsichtlich einer einfacheren Bau-Reihenfolge angepasst. Teilweise sind auf den Bildern daher schon Ergebnisse aus sp\xE4teren Schritte zu sehen. Die Angaben aus dem Text sind zu befolgen.</p></div><h3 id="antennenleiter" tabindex="-1"><a class="header-anchor" href="#antennenleiter" aria-hidden="true">#</a> Antennenleiter</h3><p>Wir beginnen mit dem Dipol-Teil der Antenne und messen hierf\xFCr 43,5 cm vom Kabelende aus gesehen ab und entfernen vorsichtig den Mantel und das Schirm-Geflecht vom Kabel. <strong>Wichtig</strong>: der wei\xDFe bzw. durchsichtige Innenleiter bleibt dabei dran! Es bleibt nur der Innenleiter vom Kabel \xFCbrig. Dies ist der eine Schenkel des Dipols.</p><p>Danach messen wir 45 cm ab der aufgetrennten Stelle bzw. 88,5 cm von der Spitze der Antenne ab und markieren uns diese Stelle. Dieses St\xFCck Koaxkabel ist der zweite Dipolschenkel.</p><p>Sp\xE4ter sieht dies dann so aus: 43,5 cm reiner Innenleiter, 45 cm Koax mit Schirm, Mantelwellensperre:</p><p><img src="'+h+'" alt="Foto Kabelende abisoliert"></p><h3 id="mantelwellensperre" tabindex="-1"><a class="header-anchor" href="#mantelwellensperre" aria-hidden="true">#</a> Mantelwellensperre</h3><p>Gleich bohren wir drei L\xF6cher mit einem Durchmesser von 3 mm in den Spulenk\xF6rper:</p><ul><li>2 L\xF6cher gleichm\xE4\xDFig auf der L\xE4ngs-Achse des Rohrs mit einem Abstand von 27 mm zueinander. Diese dienen als Anfangs- und End-Punkt der Spule und das Koaxkabel wird durch diese gef\xFChrt. <strong>Wichtig: Hinweis unten beachten</strong></li><li>1 Loch etwas weiter nach au\xDFen und in der N\xE4he des Koax-Lochs. Hier wird sp\xE4ter die Schnur zum Aufh\xE4ngen der Antenne befestigt.</li></ul><p><img src="'+n+'" alt="Foto gewickelte Spule"></p><div class="custom-container tip"><p class="custom-container-title">Hinweis</p><p>Je nach Toleranzen des Koax kann der Au\xDFendurchmesser abweichen. Dies hat zwei Folgen:</p><ol><li>Ggf. m\xFCssen die Lochdurchmesser etwas vergr\xF6\xDFert werden. Hierzu reicht es in der Regel, den Bohrer beim Bohren schr\xE4g in einer Kreisbewegung zu bewegen und damit den Lochdurchmesser zu weiten.</li><li>Die Abst\xE4nde der beiden L\xF6cher k\xF6nnen von den Angaben oben abweichen. Hier hat sich bew\xE4hrt, erst das &quot;obere&quot; Loch (zur Antennenspitze) zu bohren, das Koax testweise als Spule zu wickeln und dann passgenau das zweite Loch zu bohren. Das Verfahren ist unten genauer beschrieben.</li></ol></div><p>Los geht&#39;s!</p><p>Zun\xE4chst markieren wir uns f\xFCr das &quot;obere&quot; Ende der Spule (in Richtung Antennenspitze) das Loch f\xFCr das Koax (ca. 1 cm vom Rand des Spulenk\xF6rpers entfernt) und das Loch f\xFCr die Schnur in der N\xE4he aber etwas weiter zum Rand. Mit dem Bohrer bohren wir beide L\xF6cher.</p><p>Als n\xE4chstes f\xFChren wir das Koaxkabel durch das entsprechende Loch und zwar so, dass unsere gesetzte Markierung bei 88,5 cm von der Antennenspitze <strong>innen</strong> im Spulenk\xF6rper genau beim Loch anliegt. Das Koax sollte mit minimaler Reibung durch das Loch passen. Wenn man stark schieben oder ziehen muss, muss das Loch leicht vergr\xF6\xDFert werden. Das Kabel kann entweder von au\xDFen mit der Antennenspitze durch das Loch gef\xFChrt werden. Oder von innen mit dem Ende das sp\xE4ter den BNC-Stecker bekommt. Wichtig ist, darauf zu achten, dass man an der Stelle, wo nur noch der Innenleiter \xFCbrig ist, nicht zu stark schiebt oder zieht und damit den Innenleiter dehnt oder abrei\xDFt.</p><p>Nun wickeln wir mit dem langen St\xFCck Koax 9 Windungen \xFCber den Spulenk\xF6rper. Die Windungen sollten eng am Spulenk\xF6rper und an den benachbarten Koax-Windungen anliegen.</p><p>Nach 9 Windungen bestimmen wir die Postion des zweiten Lochs und markieren uns diese.</p><p>Wir wickeln einige Windungungen ab oder lockern diese, um Platz zum Bohren zu haben und bohren das Loch.</p><p>Als n\xE4chstes stellen wir die 9 Windungen der Mantelwellensperre wieder her und f\xFChren das Ende des langen Koax-St\xFCcks von au\xDFen durch das Loch. Mit etwas Geduld und Geschick schieben wir das Koax noch so zurecht, dass alle Windungen stramm und einheitlich sitzen.</p><p>Jetzt befestigen wir noch die Schnur mit einem Ende am Spulenk\xF6rper. Fertig.</p><p><img src="'+n+'" alt="Foto gewickelte Spule"></p><h3 id="schrumpfschlauche" tabindex="-1"><a class="header-anchor" href="#schrumpfschlauche" aria-hidden="true">#</a> Schrumpfschl\xE4uche</h3><p>Als n\xE4chstes werden Spule und Kabel mit Schrumpfschlauch versehen.</p><p><img src="'+c+'" alt="Foto Schrumpfschlauch vor dem Schrumpfen"></p><p>Als erstes wird der gro\xDFe Schrumpfschlauch \xFCber die Spule geschoben und mit Hei\xDFluft verschrumpft.</p><p><strong>Wichtig: Das Bild oben zeigt schon beide Schrumpfschl\xE4uche \xFCber Spule und Kabel. Zun\xE4chst nur die Spule zu bearbeiten hat sich in der Praxis bew\xE4hrt, weil man dann nicht aus Versehen den anderen Schrumpfschlauch schrumpft.</strong></p><p>Als n\xE4chstes den d\xFCnnen Schrumpfschlauch \xFCber die Schnur <strong>und</strong> das Ende mit dem abisolierten Kabel ziehen. Dies ist etwas fummelig und kann auch etwas dauern, vor allem mit der Schnur. Am Ende noch einmal darauf achten, dass die Schnur stramm zum Aufh\xE4ngen dient und das Kabel ohne mechanische Spannung entlang der Schnur im Schrumpfschlauch liegt. Dies geht am einfachsten, wenn man die Mantelwellensperre festh\xE4lt und am oberen Ende der Schnur zieht und dabei Schrumpfschlauch und Kabel noch einmal zurechtr\xFCckt.</p><p>Zum Abschluss dann auch diesen Schrumpfschlauch schrumpfen.</p><p><img src="'+u+'" alt="Foto Schrumpfschlauch nach dem Schrumpfen"></p><h3 id="schlaufe" tabindex="-1"><a class="header-anchor" href="#schlaufe" aria-hidden="true">#</a> Schlaufe</h3><p>Damit die Antenne aufgeh\xE4ngt werden kann, m\xFCssen wir mit der \xFCbersch\xFCssigen Schnur noch eine Schleife binden. Daf\xFCr wurde bei diesem Foto der \u201EPerfection Loop\u201C-Knoten genutzt (auf YouTube gibt es Videos dazu) und anschlie\xDFend die restliche Schnur abgeschnitten.</p><p><img src="'+m+'" alt="Foto der angebundene Schnur mit Schleife"></p><h3 id="bnc-stecker-anbringen" tabindex="-1"><a class="header-anchor" href="#bnc-stecker-anbringen" aria-hidden="true">#</a> BNC-Stecker anbringen</h3><p>Als n\xE4chstes bringen wir den BNC-Stecker am Ende des Kabels an.</p><p><strong>Wichtig: Bei Crimp-Steckern wird JETZT die Ferrule (H\xFClse) richtig herum \xFCber das Kabel geschoben. Nicht vergessen! \u{1F609}</strong></p><p>Danach m\xFCssen wir das Kabel in verschiedenen Tiefen abisolieren.</p><p>In diesem Beispiel nutzen wir einen BNC-Stecker mit einem kleinen L\xF6tfenster, in dem das Kupfer angel\xF6tet werden muss. Es gibt aber auch andere Stecker, die nur gecrimpt werden m\xFCssen.</p><p><img src="'+o+'" alt="Foto BNC-Stecker Anbringung"></p><p>F\xFCr unseren Stecker m\xFCssen wir am Ende lediglich ein kleines St\xFCck Kupfer vollst\xE4ndig abisolieren, damit es angel\xF6tet werden kann. Der Kupferteil sollte dabei nur so lang sein, dass es im Kontakt liegt. Die wei\xDFe bzw. transparente Innenisolierung sollte so lang sein, dass sie durch das Rohr geht und im L\xF6tfenster minimal herausguckt. Dadurch wird sichergestellt, dass der Innenleiter des Kabels innerhalb des Rohrs keinen Kontakt zum Geh\xE4use bekommt. Das Schirmgeflecht sollte dann \xFCber den geriffelten Teil des Rohrs gef\xFChrt werden. Der Kabelmantel sollte direkt am \xE4u\xDFeren Ende des Rohrs abschlie\xDFen.</p><p>Nach dem L\xF6ten des Innenleiters wird der Mantel mit der Ferrule vercrimpt.</p><h3 id="abschluss-und-messung" tabindex="-1"><a class="header-anchor" href="#abschluss-und-messung" aria-hidden="true">#</a> Abschluss und Messung</h3><p>Zum Abschluss bringen wir noch einen Klett-Kabelbinder an und haben unsere Antenne fertig gebaut.</p><p><img src="'+e+'" alt="Fertig gebaute Antenne"></p><p>Es macht Sinn, die Antenne mit einem Antennenanalyzer (z. B. dem NanoVNA) f\xFCr das 2m und 70cm Band zu \xFCberpr\xFCfen. Hierbei ist allerdings zu beachten, dass Gegenst\xE4nde in der N\xE4he einen gro\xDFen Einfluss auf die Antenne haben. Dies kann auch live auf dem Analyzer beobachtet werden. Am Ende l\xE4sst sich keine perfekte Aussage treffen, wie optimal die Antenne f\xFCr den jeweiligen Einsatzort abgestimmt ist. In der Praxis hat sich gezeigt, dass es immer &quot;gut genug&quot; funktioniert.</p>',57),b=[g];function f(w,k){return r(),t("div",null,b)}var z=i(p,[["render",f],["__file","t2lt.html.vue"]]);export{z as default};
